      out.write("    <script>\r\n");
      out.write("        document.getElementById('sidebarToggle').addEventListener('click', () => {\r\n");
      out.write("            document.getElementById('sidebar').classList.toggle('collapsed');\r\n");
      out.write("            document.getElementById('mainWrapper').classList.toggle('expanded');\r\n");
      out.write("        });\r\n");
      out.write("\r\n");
      out.write("        const tabla         = document.getElementById('tablaPacientes');\r\n");
      out.write("        const filas         = tabla.querySelectorAll('tbody tr');\r\n");
      out.write("        const contador      = document.getElementById('contadorPacientes');\r\n");
      out.write("        const sinResultados = document.getElementById('sinResultados');\r\n");
      out.write("        const inputBuscar   = document.getElementById('buscarPaciente');\r\n");
      out.write("        const botonesFiltro = document.querySelectorAll('.filtro-btn');\r\n");
      out.write("\r\n");
      out.write("        let filtroLetra   = 'todos';\r\n");
      out.write("        let textoBusqueda = '';\r\n");
      out.write("\r\n");
      out.write("        function actualizarContador() {\r\n");
      out.write("            const visibles = tabla.querySelectorAll('tbody tr:not([style*=\"none\"])').length;\r\n");
      out.write("            contador.textContent = visibles + ' pacientes';\r\n");
      out.write("            sinResultados.style.display = visibles === 0 ? 'block' : 'none';\r\n");
      out.write("            tabla.style.display         = visibles === 0 ? 'none'  : 'table';\r\n");
      out.write("        }\r\n");
      out.write("\r\n");
      out.write("        function filtrar() {\r\n");
      out.write("            const termino = textoBusqueda.toLowerCase().normalize('NFD').replace(/[\\u0300-\\u036f]/g, '');\r\n");
      out.write("            filas.forEach(fila => {\r\n");
      out.write("                const nombre    = (fila.dataset.nombre    || '').toLowerCase().normalize('NFD').replace(/[\\u0300-\\u036f]/g, '');\r\n");
      out.write("                const documento = (fila.dataset.documento || '').toLowerCase();\r\n");
      out.write("                const eps       = (fila.dataset.eps       || '').toLowerCase();\r\n");
      out.write("                const primera   = nombre.charAt(0);\r\n");
      out.write("                let pasaLetra = true;\r\n");
      out.write("                if (filtroLetra === 'A') pasaLetra = primera >= 'a' && primera <= 'm';\r\n");
      out.write("                else if (filtroLetra === 'N') pasaLetra = primera >= 'n' && primera <= 'z';\r\n");
      out.write("                const pasaTexto = !termino || nombre.includes(termino) || documento.includes(termino) || eps.includes(termino);\r\n");
      out.write("                fila.style.display = (pasaLetra && pasaTexto) ? '' : 'none';\r\n");
      out.write("            });\r\n");
      out.write("            actualizarContador();\r\n");
      out.write("        }\r\n");
      out.write("\r\n");
      out.write("        botonesFiltro.forEach(btn => {\r\n");
      out.write("            btn.addEventListener('click', () => {\r\n");
      out.write("                botonesFiltro.forEach(b => b.classList.remove('filtro-activo'));\r\n");
      out.write("                btn.classList.add('filtro-activo');\r\n");
      out.write("                filtroLetra = btn.dataset.filtro;\r\n");
      out.write("                filtrar();\r\n");
      out.write("            });\r\n");
      out.write("        });\r\n");
      out.write("\r\n");
      out.write("        inputBuscar.addEventListener('input', e => { textoBusqueda = e.target.value; filtrar(); });\r\n");
      out.write("        actualizarContador();\r\n");
      out.write("    </script>\r\n");
      out.write("    ");
