      out.write("  kEl('kira-btn').addEventListener('click', kToggle);\n");
      out.write("  /* Header */\n");
      out.write("  kEl('kira-btn-close').addEventListener('click', kToggle);\n");
      out.write("  kEl('kira-btn-restart').addEventListener('click', function(){ kRestart(false); });\n");
      out.write("  /* Lang pills */\n");
      out.write("  document.querySelectorAll('.kira-lang-pill').forEach(function(p){\n");
      out.write("    p.addEventListener('click', function(){ kChangeLang(p.getAttribute('data-lang')); });\n");
      out.write("    p.classList.toggle('kira-lang-active', p.getAttribute('data-lang')===KIRA.lang);\n");
      out.write("  });\n");
      out.write("  /* Input */\n");
      out.write("  kEl('kira-send').addEventListener('click', kSend);\n");
      out.write("  kEl('kira-input').addEventListener('keydown', function(e){\n");
      out.write("    if(e.key==='Enter'&&!e.shiftKey){ e.preventDefault(); kSend(); }\n");
      out.write("  });\n");
      out.write("  kEl('kira-input').addEventListener('input', function(){\n");
      out.write("    this.style.height=''; this.style.height=Math.min(this.scrollHeight,80)+'px';\n");
      out.write("  });\n");
      out.write("  /* Placeholder / status */\n");
